impl OpenFocus {
    fn effect(self) -> Option<PendingEffect<Machine>> {
        match self {
            OpenFocus::Calendar => Some(focus_calendar_effect()),
            OpenFocus::Trigger => Some(restore_focus_to_trigger_effect()),
            OpenFocus::Input => Some(restore_focus_to_input_effect()),
            OpenFocus::None => None,
        }
    }
