/// Returns the calendar system requested by the `u-ca-*` Unicode extension.
#[must_use]
pub fn calendar_extension(&self) -> Option<&str> {
    self.0
        .extensions
        .unicode
        .keywords
        .get(&icu::locale::extensions::unicode::key!("ca"))
        .and_then(|value| {
            value
